export const RecommendedArtists = ({ userInfo, loading }) => {
	return (
		<div className="list-container">
			{loading ? (
				<h3>Loading...</h3>
			) : (
				userInfo.recommended?.map((item, i) => (
					<div className="single-item" key={i}>
						<a href="#">
							<p>{item}</p>
						</a>
					</div>
				))
			)}
		</div>
	);
};
